#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
#define ls(x) x<<1
#define rs(x) x<<1|1
CI mx=1e5+5;
int n,m;
int a[mx],d[mx];
struct st
{
	int l,r,s,ad;
}t[mx*4];
void pd(int p)
{
	if(t[p].ad)
	{
		t[ls(p)].ad+=t[p].ad;
		t[rs(p)].ad+=t[p].ad;
		t[ls(p)].s+=(t[ls(p)].r-t[ls(p)].l+1)*t[p].ad;
		t[rs(p)].s+=(t[rs(p)].r-t[rs(p)].l+1)*t[p].ad;
		t[p].ad=0;
	}
}
void bd(int p,int l,int r)
{
	t[p].l=l;
	t[p].r=r;
	t[p].ad=0;
	if(l==r)
	{
		t[p].s=d[l];
		return;
	}
	int mid=(l+r)/2;
	bd(ls(p),l,mid);
	bd(rs(p),mid+1,r);
	t[p].s=t[ls(p)].s+t[rs(p)].s;
}
void up(int p,int l,int r,int x)
{
	if(l<=t[p].l&&t[p].r<=r)
	{
		t[p].s+=(t[p].r-t[p].l+1)*x;
		t[p].ad+=x;
		return;
	}
	pd(p);
	int mid=(t[p].l+t[p].r)/2;
	if(l<=mid)up(ls(p),l,r,x);
	if(r>mid)up(rs(p),l,r,x);
	t[p].s=t[ls(p)].s+t[rs(p)].s;
}
int qry(int p,int l,int r)
{
	if(l<=t[p].l&&t[p].r<=r)
	{
		return t[p].s;
	}
	pd(p);
	int mid=(t[p].l+t[p].r)/2;
	int res=0;
	if(l<=mid)res+=qry(ls(p),l,r);
	if(r>mid)res+=qry(rs(p),l,r);
	return res;
}
signed main(void)
{
	IOS
	cin>>n>>m;
	FOR(i,1,n)
	{
		cin>>a[i];
	}
	d[1]=a[1];
	FOR(i,2,n)
	{
		d[i]=a[i]-a[i-1];
	}
	bd(1,1,n);
	wh(m--)
	{
		int op;
		cin>>op;
		if(op==1)
		{
			int l,r,k,dd;
			cin>>l>>r>>k>>dd;
			up(1,l,l,k);
			if(l+1<=r)up(1,l+1,r,dd);
			if(r<n)
			{
				int v=-(dd*(r-l)+k);
				up(1,r+1,r+1,v);
			}
		}
		else
		{
			int p;
			cin>>p;
			cout<<qry(1,1,p)<<'\n';
		}
	}
	return 0;
}
